-- Rollback for 00100_certifications_v1_expansion.sql
--
-- Deletes all newly inserted certs, restores the 17 preserved rows to their
-- pre-migration names/categories/sort_orders, drops the subcategory column
-- and the supporting index. Self-contained — no manual steps required.
--
-- NOTE: profile.certification_ids arrays and dayworks.required_certification_ids
-- arrays may contain UUIDs from the newly-inserted set (e.g. if any crew selected
-- a V1 cert post-migration). Those UUIDs will remain in those arrays but will no
-- longer resolve to canonical rows. This is acceptable for a rollback and matches
-- the behaviour of migration 00062 (removed STCW certs).

drop index if exists public.idx_certifications_category_subcategory;

